import { useState } from "react";
import { useNavigate } from "react-router-dom";
import "../styles/CreateWill.css";

function CreateWill() {
  const [wills, setWills] = useState([]);
  const [text, setText] = useState("");
  const [editIndex, setEditIndex] = useState(null);

  const navigate = useNavigate();

  const addWill = () => {
    if (editIndex !== null) {
      const updated = [...wills];
      updated[editIndex] = text;
      setWills(updated);
      setEditIndex(null);
    } else {
      setWills([...wills, text]);
    }
    setText("");
  };

  const deleteWill = (index) => {
    setWills(wills.filter((_, i) => i !== index));
  };

  const editWill = (index) => {
    setText(wills[index]);
    setEditIndex(index);
  };

  return (
    <div className="create-container">
      <h2>Create Digital Will</h2>

      <textarea
        value={text}
        onChange={(e) => setText(e.target.value)}
        placeholder="Write your will..."
      />

      <button onClick={addWill}>
        {editIndex !== null ? "Update Will" : "Add Will"}
      </button>

      <button onClick={() => navigate("/dashboard")}>
        Analyze with AI
      </button>

      <h3>Saved Wills</h3>

      {wills.map((w, index) => (
        <div key={index} className="will-box">
          <p>{w}</p>
          <button onClick={() => editWill(index)}>Edit</button>
          <button onClick={() => deleteWill(index)}>Delete</button>
        </div>
      ))}
    </div>
  );
}

export default CreateWill;
